INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, phone, website, halal_certified, place_type, category_id, published, created_at) VALUES ('islam-food-42', 'Islam Food', 'Long-established restaurant operating since 1950 serving beef buns, fried dumplings, soy milk, dim sum, and noodles. Located in Kowloon with extensive menu featuring traditional Chinese halal preparations.', 'Kowloon, Hong Kong', 'Hong Kong', 'China', 22.3193000, 114.1694000, '+852 2388 7790', NULL, 1, 'restaurant', (SELECT id FROM categories WHERE slug = 'restaurant' LIMIT 1), 1, '2025-10-27T14:01:47.211Z');
INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, phone, website, halal_certified, place_type, category_id, published, created_at) VALUES ('carousel-buffet-44', 'Carousel Buffet', 'Located at Royal Plaza on Scotts in Singapore, Carousel is an award-winning buffet restaurant known for its extensive international selection. The menu brings together culinary traditions from around the world, featuring seafood on ice, Japanese sushi and sashimi, Mediterranean dishes, Asian specialties, and an array of desserts. The dining area is designed with open kitchens that allow guests to see the chefs at work, adding a lively element to the experience. Carousel is a halal-certified restaurant, making it a popular choice for diverse diners seeking quality and variety in a refined hotel setting.', '25 Scotts Rd, Royal Plaza, Singapore 228220', 'Singapore', 'Singapore', 1.3071091, 103.8320749, '+65 6589 7799', 'https://carouselbuffet.com.sg/', 1, 'restaurant', (SELECT id FROM categories WHERE slug = 'restaurant' LIMIT 1), 1, '2025-10-29T01:10:40.270Z');
INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, phone, website, halal_certified, place_type, category_id, published, created_at) VALUES ('the-white-label-singapore-city-48', 'The White Label', 'Situated along North Bridge Road in Singapore, The White Label offers French-inspired cuisine with a contemporary twist, blending European techniques with Asian influences. The restaurant’s elegant white-themed interior creates a calm and refined atmosphere, suitable for both casual gatherings and special occasions. Its halal-certified menu features a selection of pasta, seafood, and meat dishes prepared with attention to presentation and flavor balance, reflecting a modern take on classic French dining.', '101 Jln Sultan, #01-02 The Sultan, Singapore 199002', 'Singapore', 'Singapore', 1.3029698, 103.8610460, '+65 82022358', 'https://thewhitelabel.sg/', 1, 'restaurant', (SELECT id FROM categories WHERE slug = 'restaurant' LIMIT 1), 1, '2025-12-02T16:53:18.936Z');
INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, phone, website, halal_certified, place_type, category_id, published, created_at) VALUES ('warung-leko-singapore-city-49', 'Warung Leko', 'Established in 2006 in Surabaya, Indonesia, Warung Leko started as a small local eatery known for its signature dish, iga penyet (smashed beef ribs). The restaurant built its reputation around this specialty, which later became a defining feature of the brand. Over time, Warung Leko expanded to more than 40 outlets across Indonesia and opened an international branch in Singapore.

The menu focuses on Indonesian comfort food, with an emphasis on slow-cooked beef ribs served with sambal and traditional accompaniments. Recipes are based on established Indonesian cooking methods, highlighting bold spices and familiar flavors commonly found in Javanese cuisine.

Warung Leko’s Singapore outlet, located at Bugis Village, follows the same concept and menu approach as its Indonesian counterparts, offering dishes prepared using the original recipes developed in Surabaya.', '162 Rochor Rd, Singapore 188437', 'Singapore', 'Singapore', 1.3008012, 103.8553687, '8503 7499', 'https://www.warungleko.sg', 0, 'restaurant', (SELECT id FROM categories WHERE slug = 'restaurant' LIMIT 1), 1, '2025-12-31T02:06:24.343Z');
