INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, phone, website, halal_certified, place_type, category_id, published, created_at) VALUES ('tokyo-shokudo-city-square-mall-singapore-city-98', 'Tokyo Shokudo - City Square Mall', 'Tokyo Shokudo - City Square Mall is a halal-certified Japanese restaurant in Singapore that focuses on everyday Japanese comfort food. The menu features familiar dishes such as ramen, udon, donburi, curry rice, and set meals inspired by casual eateries commonly found in Japan. Recipes are adapted to meet halal requirements while maintaining traditional Japanese cooking styles and flavor profiles.

