INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, phone, website, halal_certified, place_type, category_id, published, created_at) VALUES ('sukiya-suntec-city-singapore-city-132', 'SUKIYA Suntec City', 'Sukiya is a Japanese restaurant chain known for gyudon, a dish consisting of thinly sliced beef and onions simmered in a soy sauce–based savory sauce, served over Japanese short-grain rice. Gyudon is commonly eaten as a quick and filling meal, particularly during lunch hours.

The dish is offered in multiple portion sizes and can be customized with additional toppings such as kimchi or cheese. Sukiya’s menu is centered on simple Japanese comfort food, with an emphasis on consistency and efficiency. Ingredients, including beef and rice, are selected and monitored by the brand’s internal quality control processes to meet its preparation standards.', '3 Temasek Boulevard #B1-158 Suntec City, Singapore 038983', 'Singapore', 'Singapore', 1.2957510, 103.8588770, NULL, NULL, 1, 'restaurant', (SELECT id FROM categories WHERE slug = 'restaurant' LIMIT 1), 1, '2026-01-11T10:14:41.691Z');
