INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, halal_certified, place_type, category_id, published, created_at) VALUES ('masjid-mukaram-bang-tao-p4', 'Masjid Mukaram Bang Tao', 'Mosque serving the Muslim community in the Bang Tao area of Phuket. Provides daily prayer services. Facilities: Ablution facilities.', 'Bang Tao, Thalang District, Phuket 83110, Thailand', 'Phuket', 'Thailand', 8.0257000, 98.2967000, 1, 'mosque', (SELECT id FROM categories WHERE slug = 'mosque' LIMIT 1), 1, '2025-10-27T14:01:47.211Z');
INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, halal_certified, place_type, category_id, published, created_at) VALUES ('tokyo-camii-p5', 'Tokyo Camii', 'Largest mosque in Japan, built in 2000. Features Ottoman-Turkish architectural style with a prayer hall, cultural center, and library. Facilities: Ablution facilities, Separate prayer areas, Library.', '1-19 Oyama-cho, Shibuya-ku, Tokyo 151-0065, Japan', 'Tokyo', 'Japan', 35.6682000, 139.7077000, 1, 'mosque', (SELECT id FROM categories WHERE slug = 'mosque' LIMIT 1), 1, '2025-10-27T14:01:47.211Z');
INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, halal_certified, place_type, category_id, published, created_at) VALUES ('kobe-mosque-p6', 'Kobe Mosque', 'Oldest mosque in Japan, established in 1935. Serves the Muslim community in the Kansai region. Facilities: Ablution facilities, Separate prayer areas.', '2-25-14 Nakayamate-dori, Chuo-ku, Kobe 650-0004, Japan', 'Kobe', 'Japan', 34.6936000, 135.1851000, 1, 'mosque', (SELECT id FROM categories WHERE slug = 'mosque' LIMIT 1), 1, '2025-10-27T14:01:47.211Z');
INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, halal_certified, place_type, category_id, published, created_at) VALUES ('xiaotaoyuan-mosque-p7', 'Xiaotaoyuan Mosque', 'Historic mosque in Shanghai, established in 1917. Located in the former French Concession area, serves the local Muslim community. Facilities: Ablution facilities, Separate prayer areas.', '52 Xiaotaoyuan Street, Huangpu District, Shanghai 200020, China', 'Shanghai', 'China', 31.2222000, 121.4692000, 1, 'mosque', (SELECT id FROM categories WHERE slug = 'mosque' LIMIT 1), 1, '2025-10-27T14:01:47.211Z');
INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, halal_certified, place_type, category_id, published, created_at) VALUES ('kowloon-masjid-and-islamic-centre-p8', 'Kowloon Masjid and Islamic Centre', 'Largest mosque in Hong Kong, rebuilt in 1984. Located on Nathan Road in Tsim Sha Tsui, serves the Muslim community with prayer facilities and educational programs. Facilities: Ablution facilities, Separate prayer areas, Library, Community hall.', '105 Nathan Road, Tsim Sha Tsui, Kowloon, Hong Kong', 'Hong Kong', 'China', 22.2978000, 114.1722000, 1, 'prayer_room', (SELECT id FROM categories WHERE slug = 'other' LIMIT 1), 1, '2025-10-27T14:01:47.211Z');
INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, halal_certified, place_type, category_id, published, created_at) VALUES ('masjid-moulana-mohamed-ali-p9', 'Masjid Moulana Mohamed Ali', 'Masjid Moulana Mohamed Ali (Moulana Mohamed Ali Mosque) sometimes shortened to Moulana Mohd Ali is an underground mosque in Raffles Place, Singapore. Formerly a pair of shophouses located along Market Street that were converted into prayer halls, the mosque is now located in the basement of UOB Plaza One. It is the only underground mosque in Singapore. ', '80 Raffles Pl, #B1-01 I UOB Plaza, Singapore 048624', 'Singapore', 'Singapore', 1.2855981, 103.8500704, 1, 'mosque', (SELECT id FROM categories WHERE slug = 'mosque' LIMIT 1), 1, '2025-10-27T17:37:14.121Z');
INSERT OR IGNORE INTO places (slug, name, description, address, city, country, lat, lng, halal_certified, place_type, category_id, published, created_at) VALUES ('masjid-al-muttaqin-p10', 'Masjid Al-Muttaqin', 'Masjid Al-Muttaqin (Al-Muttaqin Mosque) is a community-focused mosque in Ang Mo Kio, Singapore. The chosen name Al-Muttaqin refers to the pious people who are ever aware of God the Almighty. ', '5140 Ang Mo Kio Ave 6, S 569844', 'Singapore', 'Singapore', 1.3702576, 103.8460620, 1, 'mosque', (SELECT id FROM categories WHERE slug = 'mosque' LIMIT 1), 1, '2026-01-24T12:05:38.587Z');

